"use client";

import { useState } from "react";
import { Vehicle } from "@prisma/client";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  useReactTable,
} from "@tanstack/react-table";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { vehicleSchema, VehicleFormValues } from "@/lib/validations";
import { createVehicle, deleteVehicle } from "@/server/actions/vehicle.actions";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";

export const columns: ColumnDef<Vehicle>[] = [
  {
    accessorKey: "registrationNo",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Registration No</span>,
    cell: ({ row }) => <span className="font-medium">{row.getValue("registrationNo")}</span>
  },
  {
    accessorKey: "name",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Vehicle Name</span>,
  },
  {
    accessorKey: "type",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Type</span>,
  },
  {
    accessorKey: "capacityKg",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Capacity (kg)</span>,
  },
  {
    accessorKey: "status",
    header: () => <span className="uppercase tracking-wider text-xs font-semibold text-muted-foreground">Status</span>,
    cell: ({ row }) => {
      const status = row.getValue("status") as string;
      return (
        <span className={`px-2.5 py-1 rounded-full text-[10px] uppercase font-bold tracking-wider ${
          status === 'available' ? 'bg-[#2eb85c]/10 text-[#2eb85c]' :
          status === 'on_trip' ? 'bg-[#3399ff]/10 text-[#3399ff]' :
          status === 'in_shop' ? 'bg-[#f9b115]/10 text-[#f9b115]' :
          'bg-[#e55353]/10 text-[#e55353]'
        }`}>
          {status.replace("_", " ")}
        </span>
      );
    }
  },
  {
    id: "actions",
    cell: ({ row }) => {
      const vehicle = row.original;
      return (
        <Button variant="destructive" size="sm" onClick={async () => {
          if (confirm("Are you sure?")) {
            await deleteVehicle(vehicle.id);
          }
        }}>
          Delete
        </Button>
      );
    },
  },
];

export function FleetClient({ data }: { data: Vehicle[] }) {
  const [open, setOpen] = useState(false);
  const [error, setError] = useState("");

  const table = useReactTable({
    data,
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  const {
    register,
    handleSubmit,
    control,
    reset,
    formState: { errors, isSubmitting },
  } = useForm<VehicleFormValues>({
    resolver: zodResolver(vehicleSchema) as any,
    defaultValues: {
      status: "available",
      odometer: 0,
      acquisitionCost: 0,
    }
  });

  const onSubmit = async (values: VehicleFormValues) => {
    setError("");
    const result = await createVehicle(values);
    if (result.success) {
      setOpen(false);
      reset();
    } else {
      setError(result.error || "Failed to create vehicle");
    }
  };

  return (
    <Card className="shadow-sm border-border overflow-hidden">
      <CardHeader className="border-b bg-card px-6 py-4 flex flex-row items-center justify-between">
        <div>
          <CardTitle className="text-xl font-medium tracking-tight">Fleet Management</CardTitle>
          <p className="text-sm text-muted-foreground mt-1">
            Manage your vehicles and their current status.
          </p>
        </div>
        <Dialog open={open} onOpenChange={setOpen}>
          <DialogTrigger render={<Button />}>
            Add Vehicle
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Add New Vehicle</DialogTitle>
            </DialogHeader>
            <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
              {error && <p className="text-sm text-red-500">{error}</p>}
              
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Registration No</Label>
                  <Input {...register("registrationNo")} />
                  {errors.registrationNo && <p className="text-xs text-red-500">{errors.registrationNo.message}</p>}
                </div>
                <div className="space-y-2">
                  <Label>Vehicle Name</Label>
                  <Input {...register("name")} />
                  {errors.name && <p className="text-xs text-red-500">{errors.name.message}</p>}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Type</Label>
                  <Controller
                    control={control}
                    name="type"
                    render={({ field }) => (
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <SelectTrigger>
                          <SelectValue placeholder="Select type" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="VAN">Van</SelectItem>
                          <SelectItem value="TRUCK">Truck</SelectItem>
                          <SelectItem value="MINI">Mini</SelectItem>
                        </SelectContent>
                      </Select>
                    )}
                  />
                  {errors.type && <p className="text-xs text-red-500">{errors.type.message}</p>}
                </div>
                <div className="space-y-2">
                  <Label>Capacity (kg)</Label>
                  <Input type="number" {...register("capacityKg")} />
                  {errors.capacityKg && <p className="text-xs text-red-500">{errors.capacityKg.message}</p>}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Region</Label>
                  <Input {...register("region")} />
                  {errors.region && <p className="text-xs text-red-500">{errors.region.message}</p>}
                </div>
                <div className="space-y-2">
                  <Label>Status</Label>
                  <Controller
                    control={control}
                    name="status"
                    render={({ field }) => (
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <SelectTrigger>
                          <SelectValue placeholder="Select status" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="available">Available</SelectItem>
                          <SelectItem value="in_shop">In Shop</SelectItem>
                          <SelectItem value="retired">Retired</SelectItem>
                        </SelectContent>
                      </Select>
                    )}
                  />
                </div>
              </div>

              <Button type="submit" className="w-full" disabled={isSubmitting}>
                {isSubmitting ? "Saving..." : "Save Vehicle"}
              </Button>
            </form>
          </DialogContent>
        </Dialog>
      </CardHeader>

      <CardContent className="p-0">
        <Table>
          <TableHeader className="bg-muted/30">
            {table.getHeaderGroups().map((headerGroup) => (
              <TableRow key={headerGroup.id}>
                {headerGroup.headers.map((header) => {
                  return (
                    <TableHead key={header.id} className="h-10">
                      {header.isPlaceholder
                        ? null
                        : flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )}
                    </TableHead>
                  )
                })}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {table.getRowModel().rows?.length ? (
              table.getRowModel().rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-state={row.getIsSelected() && "selected"}
                  className="hover:bg-muted/20 transition-colors"
                >
                  {row.getVisibleCells().map((cell) => (
                    <TableCell key={cell.id} className="py-3">
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  ))}
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={columns.length} className="h-24 text-center">
                  No vehicles found. Click "Add Vehicle" to register one.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}
